    Recursively merges two nested dictionaries, adding numeric values when keys conflict,
    and preferring the value from the second dictionary in non-numeric conflicts.
    """
    result = {}

    # Combine all keys from both dictionaries
    for key in set(d1) | set(d2):
        if key in d1 and key in d2:
            # If both values are numeric, add them together
            if isinstance(d1[key], (int, float)) and isinstance(d2[key], (int, float)):
                result[key] = d1[key] + d2[key]
