class Stack:
    def __init__(self):
        # Choosing list as the underlying data structure because it provides efficient append (push) and pop operations at the end.
        self.items = []

    def push(self, item):
        """Add an item to the top of the stack."""
        self.items.append(item)

    def pop(self):
        """Remove and return the item from the top of the stack. Raises IndexError if the stack is empty."""
        if not self.items:
            raise IndexError("pop from empty stack")
        return self.items.pop()

    def peek(self):
        """Return the item at the top of the stack without removing it. Raises IndexError if the stack is empty."""
        if not self.items:
            raise IndexError("peek from empty stack")
        return self.items[-1]

    def length(self):
        """Return the number of items in the stack."""
        return len(self.items)

    def empty(self):
        """Return True if the stack is empty, False otherwise."""
        return len(self.items) == 0
