def merge_dicts(d1, d2):
    """Recursively merges two nested dictionaries, adding numeric conflicts and preferring the second value for other conflicts."""

    if not isinstance(d1, dict) or not isinstance(d2, dict):
        return d2  # If either is not a dictionary, prefer the second one

    merged = {}
    all_keys = set(d1.keys()).union(set(d2.keys()))

    for key in all_keys:
        if key in d1 and key in d2:
            v1, v2 = d1[key], d2[key]
            if isinstance(v1, dict) and isinstance(v2, dict):
                merged[key] = merge_dicts(v1, v2)
            elif isinstance(v1, (int, float)) and isinstance(v2, (int, float)):
                merged[key] = v1 + v2  # Add numeric values
            else:
                merged[key] = v2  # Prefer the second value for other conflicts
        elif key in d1:
            merged[key] = d1[key]
        else:
            merged[key] = d2[key]

    return merged

