from dataclasses import dataclass

@dataclass
class Node:
    value: any
    next: 'Node' = None  # Recursive type hint for the next node

class Queue:
    def __init__(self):
        self._head: Node = None  # Head of the queue, oldest item
        self._tail: Node = None  # Tail of the queue, newest item

    def enqueue(self, value: any) -> None:
        new_node = Node(value)
        if self._tail is not None:
            self._tail.next = new_node  # Link old tail to new node
        else:
            self._head = new_node  # If queue was empty, new node is both head and tail
        self._tail = new_node  # Update tail to new node

    def dequeue(self) -> any:
        if self._head is None:
            raise IndexError("Dequeue from empty queue")
        value = self._head.value
        self._head = self._head.next  # Move head to next item
        if self._head is None:
            self._tail = None  # If now empty, reset tail
        return value

# One-line docstring summary: Linked-list backed FIFO queue with O(1) enqueue and dequeue operations
