from dataclasses import dataclass, field

@dataclass
class Node:
    value: int
    next: 'Node' = field(default=None)

class Queue:
    def __init__(self):
        self._front: Node = None  # Pointer to the front of the queue
        self._rear: Node = None   # Pointer to the rear of the queue

    def enqueue(self, value: int) -> None:
        new_node = Node(value)
        if not self._front:
            self._front = new_node
        else:
            self._rear.next = new_node
        self._rear = new_node  # Update the rear to point to the new node

    def dequeue(self) -> int:
        if not self._front:
            raise IndexError("Dequeue from empty queue")
        value = self._front.value
        self._front = self._front.next
        if not self._front:  # If dequeuing the last element
            self._rear = None
        return value

