def find_first_index(nums, target):
    left, right = 0, len(nums) - 1
    result = -1  # Initialize result to -1 if target is not found

    while left <= right:
        mid = (left + right) // 2
        if nums[mid] == target:
            result = mid  # Update result to current mid and continue searching on the left side
            right = mid - 1
        elif nums[mid] < target:
            left = mid + 1
        else:
            right = mid - 1

    return result  # Return the first index of target, or -1 if not found

# O(log n) time complexity due to binary search, O(1) space complexity
