from dataclasses import dataclass

@dataclass
class Node:
    value: int
    next: 'Node' = None  # Self-reference for the next node in the list

class Queue:
    def __init__(self):
        self._head: Node = None  # Start with an empty queue
        self._tail: Node = None  # Track the end of the queue for O(1) enqueue

    def enqueue(self, value: int) -> None:
        new_node = Node(value)
        if not self._head:
            self._head = new_node  # If the queue is empty, set both head and tail to the new node
            self._tail = new_node
        else:
            self._tail.next = new_node  # Link the current tail to the new node
            self._tail = new_node  # Move the tail pointer to the new node
        # Enqueue operation is O(1) because it involves only a few pointer changes

    def dequeue(self) -> int:
        if not self._head:
            raise IndexError("Dequeue from empty queue")  # Raise an error if trying to dequeue from an empty queue
        value = self._head.value  # Get the value of the head node
        self._head = self._head.next  # Move the head pointer to the next node
        if not self._head:
            self._tail = None  # If after dequeuing the queue becomes empty, reset tail
        return value
        # Dequeue operation is O(1) because it involves only a few pointer changes

# Summary: This implementation uses a doubly linked list where each node contains an integer value and a reference to the next node. The Queue class maintains two pointers, _head and _tail, to keep track of the start and end of the queue respectively. Enqueue appends a new node at the tail, and dequeue removes the head node, ensuring O(1) time complexity for both operations.
