def merge_dicts(d1, d2):
    """
    Recursively merges two nested dictionaries, adding numeric values when keys conflict,
    and preferring the second dictionary's value otherwise.
    """
    merged = {}
    # Collect all keys from both dictionaries
    all_keys = set(d1.keys()).union(d2.keys())

    for key in all_keys:
        if key in d1 and key in d2:
            # If values are both numbers, add them
            if isinstance(d1[key], (int, float)) and isinstance(d2[key], (int, float)):
                merged[key] = d1[key] + d2[key]
            else:
                # Otherwise, prefer the second dictionary's value
                merged[key] = d2[key]
        elif key in d1:
            # If only in the first dictionary, take its value
            merged[key] = d1[key]
        else:
            # If only in the second dictionary, take its value
            merged[key] = d2[key]

    for k, v in d2.items():
        if isinstance(v, dict):
            # Recursively merge nested dictionaries
            merged[k] = merge_dicts(merged.get(k, {}), v)
        elif isinstance(v, list):
            # Concatenate lists
            merged[k] = (merged.get(k, []) + v)

    return merged
