from dataclasses import dataclass

@dataclass
class Node:
    value: any
    next_node: 'Node' = None  # Recursive type hint for the linked list structure

class Queue:
    def __init__(self):
        self._front: Node = None  # Pointer to the front of the queue
        self._rear: Node = None   # Pointer to the rear of the queue

    def enqueue(self, item: any) -> None:
        """Adds an item to the rear of the queue."""
        new_node = Node(item)
        if not self._front:
            self._front = self._rear = new_node  # Both front and rear point to the new node
        else:
            self._rear.next_node = new_node  # Link the current rear to the new node
            self._rear = new_node  # Move the rear pointer to the new node

    def dequeue(self) -> any:
        """Removes an item from the front of the queue and returns it."""
        if not self._front:
            raise IndexError("Dequeue from empty queue")  # Raise error if queue is empty
        dequeued_item = self._front.value  # Get the value at the front
        self._front = self._front.next_node  # Move the front pointer to the next node
        if not self._front:
            self._rear = None  # If front becomes None, rear should also be None
        return dequeued_item

    def is_empty(self) -> bool:
        """Returns True if the queue is empty, False otherwise."""
        return self._front is None

    def __len__(self) -> int:
        """Returns the number of items in the queue."""
        count = 0
        current = self._front
        while current:
            count += 1
            current = current.next_node
        return count

# One-line docstring summary:
# Implements a FIFO Queue using a linked list with O(1) enqueue and dequeue operations.
