    Recursively merges two nested dictionaries, adding numeric values and 
    preferring the second dictionary's values for non-numeric conflicts.
    """

    def recursive_merge(sub_d1, sub_d2):
        # Create a new dictionary to hold merged results
        result = {}

        # Add all keys from the first dictionary to the result
        for key in sub_d1:
            if key not in sub_d2:
                result[key] = sub_d1[key]

        # Merge keys that exist in both dictionaries
        for key in sub_d2:
            if key not in sub_d1:
                result[key] = sub_d2[key]
            else:
                # If both values are numeric, add them; otherwise, take the second value
                if isinstance(sub_d1[key], (int, float)) and isinstance(sub_d2[key], (int, float)):
                    result[key] = sub_d1[key] + sub_d2[key]
                else:
                    result[key] = sub_d2[key]

        # Recursively merge nested dictionaries
        for key in set(sub_d1) & set(sub_d2):
            if isinstance(sub_d1[key], dict) and isinstance(sub_d2[key], dict):
                result[key] = recursive_merge(sub_d1[key], sub_d2[key])

        return result

    return recursive_merge(d1, d2)
