from dataclasses import dataclass

@dataclass
class Node:
    value: int
    next: 'Node' = None  # Self-reference for the next node in the list

class Queue:
    def __init__(self):
        self.head = None  # Pointer to the front of the queue
        self.tail = None  # Pointer to the back of the queue

    def enqueue(self, value: int) -> None:
        new_node = Node(value)
        if not self.head:
            self.head = self.tail = new_node  # If queue is empty, both head and tail point to new node
        else:
            self.tail.next = new_node  # Add new node after current tail
            self.tail = new_node  # Move tail pointer to the new node

    def dequeue(self) -> int:
        if not self.head:
            raise IndexError("Dequeue from empty queue")  # Handle error for dequeuing from an empty queue
        value = self.head.value  # Get the value of the front node
        self.head = self.head.next  # Move head pointer to the next node
        if not self.head:
            self.tail = None  # If head is None, tail should also be None (queue becomes empty)
        return value

# O(1) enqueue and dequeue operations using a private node dataclass
