@dataclass
class Node:
    value: int
    next: 'Node' = None

class Queue:
    def __init__(self):
        self._front = None  # Pointer to the front of the queue (head)
        self._rear = None   # Pointer to the rear of the queue (tail)

    def enqueue(self, value: int) -> None:
        """Add an element to the end of the queue."""
        new_node = Node(value)  # Create a new node with the given value
        if not self._front:
            self._front = self._rear = new_node  # If queue is empty, set both front and rear to new node
        else:
            self._rear.next = new_node  # Link new node to current rear
            self._rear = new_node  # Update rear pointer to the new node

    def dequeue(self) -> int:
        """Remove and return the element at the front of the queue."""
        if not self._front:
            raise IndexError("Dequeue from empty queue")  # Raise error if queue is empty
        value = self._front.value  # Get the value at the front
        self._front = self._front.next  # Move front pointer to next node
        if not self._front:
            self._rear = None  # If no more elements, set rear to None
        return value

