def max_two_distinct_substring(s):
    # Initialize variables to keep track of the maximum length, start index, and character count
    max_length = 0
    start = 0
    char_count = {}

    for end in range(len(s)):
        # Add the current character to the dictionary or increment its count
        if s[end] in char_count:
            char_count[s[end]] += 1
        else:
            char_count[s[end]] = 1

        # If more than two distinct characters are found, shrink the window from the left
        while len(char_count) > 2:
            char_count[s[start]] -= 1
            if char_count[s[start]] == 0:
                del char_count[s[start]]
            start += 1

        # Update the maximum length and substring
        current_length = end - start + 1
        if current_length > max_length:
            max_length = current_length
            max_substring = s[start:end+1]

    return (max_length, max_substring)
# The function uses a sliding window approach to find the longest substring with at most two distinct characters. It maintains a dictionary to count character occurrences and adjusts the window size by moving the start pointer when more than two distinct characters are found.

