def group_anagrams(words):
    # Use a dictionary to map sorted word strings to lists of anagrams
    anagram_groups = {}

    for word in words:
        # Sort the characters of the word and use it as a key
        sorted_word = ''.join(sorted(word))

        # If the sorted word is not already a key, add it with the current word as the first element
        if sorted_word not in anagram_groups:
            anagram_groups[sorted_word] = [word]
        else:
            # Otherwise, append the current word to the list of anagrams for this key
            anagram_groups[sorted_word].append(word)

    # Return each group of anagrams sorted alphabetically
    return [' '.join(sorted(group)) for group in anagram_groups.values()]

