@lru_cache(maxsize=None)  # Memoize results to optimize repeated calculations
def fibonacci(n: int) -> int:
    """Returns the nth Fibonacci number, rejecting negative inputs."""
    if n < 0:
        raise ValueError("Input must be a non-negative integer.")
    elif n == 0:
        return 0
    elif n == 1:
        return 1
    else:
        return fibonacci(n - 1) + fibonacci(n - 2)
