def merge_dicts(d1, d2):
    """
    Recursively merges two nested dictionaries, adding numeric conflicts and preferring
    the second value for other conflicts.
    """
    result = {}

    # Combine keys from both dictionaries
    all_keys = set(d1.keys()) | set(d2.keys())

    for key in all_keys:
        if key in d1 and key in d2:
            # If both values are dicts, merge recursively
            if isinstance(d1[key], dict) and isinstance(d2[key], dict):
                result[key] = merge_dicts(d1[key], d2[key])
            else:
                # Add numeric conflicts, preferring the second value for other types
                if isinstance(d1[key], (int, float)) and isinstance(d2[key], (int, float)):
                    result[key] = d1[key] + d2[key]
                else:
                    result[key] = d2[key]
        elif key in d1:
            # Take the value from the first dictionary
            result[key] = d1[key]
        else:
            # Take the value from the second dictionary
            result[key] = d2[key]

    return result

