def binary_search_first(nums, target):
    # Initialize pointers for binary search
    left, right = 0, len(nums) - 1

    # Loop until the pointers cross
    while left <= right:
        mid = (left + right) // 2  # Calculate middle index

        # If the middle element is greater than target, search in the left half
        if nums[mid] > target:
            right = mid - 1
        # If the middle element is less than target, search in the right half
        elif nums[mid] < target:
            left = mid + 1
        else:
            # If found, move left pointer to find the first occurrence
            if mid == 0 or nums[mid - 1] != target:
                return mid
            else:
                right = mid - 1

    # Return -1 if target is not found
    return -1

# Summary: Iterative binary search with a twist to handle duplicates by moving left pointer when exact match is found.
