@dataclass
class Node:
    value: int
    next: 'Node' = None  # Self-reference for the linked list structure

class FIFOQueue:
    def __init__(self):
        self.head = None  # Pointer to the front of the queue
        self.tail = None  # Pointer to the rear of the queue

    def enqueue(self, value: int) -> None:
        new_node = Node(value)
        if not self.tail:
            self.head = self.tail = new_node  # If the queue is empty, both head and tail point to the new node
        else:
            self.tail.next = new_node  # Link the current tail to the new node
            self.tail = new_node  # Move the tail pointer to the new node

    def dequeue(self) -> int:
        if not self.head:
            raise IndexError("Dequeue from empty queue")  # Raise an error if attempting to dequeue from an empty queue
        value = self.head.value  # Retrieve the value of the front node
        self.head = self.head.next  # Move the head pointer to the next node
        if not self.head:
            self.tail = None  # If the queue becomes empty, reset the tail pointer
        return value

    def __repr__(self) -> str:
        nodes = []
        current = self.head
        while current:
            nodes.append(str(current.value))
            current = current.next
        return ' -> '.join(nodes)
