        self.items = []  # Use list to store stack items

    def push(self, item):
        self.items.append(item)  # Append item to the end of the list (top of the stack)

    def pop(self):
        if not self.items:  # Check if the stack is empty
            raise IndexError("pop from empty stack")  # Raise error if stack is empty
        return self.items.pop()  # Remove and return the last item (top of the stack)

    def peek(self):
        if not self.items:  # Check if the stack is empty
            raise IndexError("peek from empty stack")  # Raise error if stack is empty
        return self.items[-1]  # Return the last item without removing it

    def length(self):
        return len(self.items)  # Return the number of items in the stack

    def empty(self):
        return len(self.items) == 0  # Check if the stack is empty

# Summary: Stack implementation using list for efficient append and pop operations.
