def merge_dicts(dict1, dict2):
    # Create a new dictionary to hold the merged result
    merged_dict = {}

    # Get all keys from both dictionaries
    all_keys = set(dict1.keys()).union(dict2.keys())

    for key in all_keys:
        if key in dict1 and key in dict2:
            # If both dictionaries have the same key, merge their values
            value1 = dict1[key]
            value2 = dict2[key]

            if isinstance(value1, dict) and isinstance(value2, dict):
                # Recursively merge nested dictionaries
                merged_dict[key] = merge_dicts(value1, value2)
            elif isinstance(value1, (int, float)) and isinstance(value2, (int, float)):
                # For numeric values, add them together
                merged_dict[key] = value1 + value2
            else:
                # For other types of conflicts, prefer the second value
                merged_dict[key] = value2
        elif key in dict1:
            # If only dict1 has the key, copy it to the result
            merged_dict[key] = dict1[key]
        else:
            # If only dict2 has the key, copy it to the result
            merged_dict[key] = dict2[key]

    return merged_dict

