from dataclasses import dataclass

@dataclass
class Node:
    value: any
    next_node: 'Node' = None  # Use forward reference for circular dependency

class FIFOQueue:
    def __init__(self):
        self._front: Node = None  # Pointer to the front of the queue
        self._rear: Node = None   # Pointer to the rear of the queue

    def enqueue(self, value: any) -> None:
        new_node = Node(value)
        if not self._front:
            self._front = self._rear = new_node  # First element in the queue
        else:
            self._rear.next_node = new_node  # Add new node to the rear
            self._rear = new_node  # Move rear pointer

    def dequeue(self) -> any:
        if not self._front:
            raise IndexError("Dequeue from empty queue")  # Queue is empty
        value = self._front.value  # Get the value of the front node
        self._front = self._front.next_node  # Move front pointer to the next node
        if not self._front:
            self._rear = None  # If now empty, reset rear pointer
        return value

    def is_empty(self) -> bool:
        return self._front is None  # Queue is empty if front is None

# One-line docstring summary: A FIFO queue implemented using a linked list with O(1) enqueue and dequeue operations.
