def group_anagrams(words):
    # Use a dictionary to map sorted characters to lists of words
    anagrams = {}

    for word in words:
        # Sort the characters in the word to use as a key
        sorted_word = ''.join(sorted(word))

        # If the sorted word is already a key, append the original word
        if sorted_word in anagrams:
            anagrams[sorted_word].append(word)
        else:
            # Otherwise, create a new key with the sorted word and add the word to its list
            anagrams[sorted_word] = [word]

    # Return each group of words sorted alphabetically
    return [sorted(group) for group in anagrams.values()]

