def binary_search_first_index(nums, target):
    left, right = 0, len(nums) - 1
    while left <= right:
        mid = (left + right) // 2
        # Check if the middle element is equal to the target and it's the first occurrence
        if nums[mid] == target and (mid == 0 or nums[mid-1] < target):
            return mid
        elif nums[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return -1

# Binary search with a twist to find the first occurrence of the target in a sorted list with duplicates.
