def merge_dictionaries(dict1, dict2):
    """
    Recursively merges two nested dictionaries, adding numeric values when keys conflict,
    and preferring the second dictionary's value otherwise.
    """

    # Create a new dictionary to hold the merged result
    merged = {}

    # Get all unique keys from both dictionaries
    keys = set(dict1.keys()).union(dict2.keys())

    for key in keys:
        if key in dict1 and key in dict2:
            # If both dictionaries have the same key, merge their values
            if isinstance(dict1[key], dict) and isinstance(dict2[key], dict):
                merged[key] = merge_dictionaries(dict1[key], dict2[key])
            elif isinstance(dict1[key], (int, float)) and isinstance(dict2[key], (int, float)):
                # If both values are numeric, add them
                merged[key] = dict1[key] + dict2[key]
            else:
                # Otherwise, prefer the value from the second dictionary
                merged[key] = dict2[key]
        elif key in dict1:
            # If only the first dictionary has the key, copy it over
            merged[key] = dict1[key]
        else:
            # If only the second dictionary has the key, copy it over
            merged[key] = dict2[key]

    return merged

