# Define a Node dataclass to hold the value and next pointer for each element in the queue
@dataclass
class Node:
    value: any
    next: 'Node' = None  # Recursive type hinting for the linked list structure

class Queue:
    def __init__(self):
        self._front: Node | None = None  # Pointer to the front of the queue
        self._rear: Node | None = None   # Pointer to the rear of the queue
        self._size: int = 0              # Keep track of the number of elements in the queue

    def enqueue(self, value):
        new_node = Node(value)          # Create a new node with the given value
        if not self._front:
            self._front = self._rear = new_node  # If queue is empty, both front and rear point to the new node
        else:
            self._rear.next = new_node      # Link the current rear node's next to the new node
            self._rear = new_node             # Update the rear pointer to the new node
        self._size += 1                     # Increment the size of the queue

    def dequeue(self) -> any | None:
        if not self._front:
            return None                   # Return None if the queue is empty
        value = self._front.value         # Get the value from the front node
        self._front = self._front.next      # Update the front pointer to the next node
        if self._front is None:
            self._rear = None             # If after dequeuing, front becomes None, set rear to None as well
        self._size -= 1                     # Decrement the size of the queue
        return value                      # Return the dequeued value

    def __len__(self) -> int:
        return self._size                   # Return the current size of the queue
