from dataclasses import dataclass, field

@dataclass
class Node:
    value: int
    next_node: 'Node' = field(default=None)

class Queue:
    def __init__(self):
        self._head: Node = None  # Pointer to the front of the queue
        self._tail: Node = None  # Pointer to the back of the queue

    def enqueue(self, value: int) -> None:
        """Add an element to the end of the queue."""
        new_node = Node(value)
        if not self._head:
            self._head = self._tail = new_node
        else:
            self._tail.next_node = new_node
            self._tail = new_node

    def dequeue(self) -> int:
        """Remove and return the element at the front of the queue."""
        if not self._head:
            raise IndexError("dequeue from empty queue")
        value = self._head.value
        self._head = self._head.next_node
        if not self._head:
            self._tail = None
        return value

# Reasoning for choices:
# - Node dataclass: Simplifies node creation and access.
# - _head and _tail pointers: Directly reference the front and back of the queue,
#   allowing O(1) enqueue and dequeue operations.
```

This implementation uses a private `Node` dataclass to store elements and two pointers, `_head` and `_tail`, to manage the queue efficiently. The `enqueue` method adds new nodes at the end, updating the `_tail`. The `dequeue` method removes nodes from the front, adjusting both pointers as needed. This ensures that both operations run in constant time, O(1).

