def invert_dict(d):
    # Initialize an empty dictionary to store the inverted mapping
    inv = {}

    # Iterate over each key-value pair in the original dictionary
    for k, v in d.items():
        if v not in inv:
            # If the value is not yet a key in inv, initialize it with an empty list
            inv[v] = []
        inv[v].append(k)  # Append the original key to the list of keys associated with this value

    # Convert each list of keys to be sorted
    for v in inv.values():
        v.sort()

    return inv

