@dataclass
class Node:
    value: int  # Value stored in the node
    next: 'Node' = None  # Reference to the next node in the queue

class Queue:
    def __init__(self):
        self.front = None  # Pointer to the front of the queue (dequeue side)
        self.back = None  # Pointer to the back of the queue (enqueue side)

    def enqueue(self, value: int) -> None:
        """Add an element to the back of the queue"""
        new_node = Node(value)  # Create a new node with the given value
        if not self.back:
            self.front = self.back = new_node  # If queue is empty, set both front and back to the new node
        else:
            self.back.next = new_node  # Add the new node after the current back
            self.back = new_node  # Move the back pointer to the new node

    def dequeue(self) -> int:
        """Remove an element from the front of the queue and return its value"""
        if not self.front:
            raise IndexError("Dequeue from empty queue")  # Check for empty queue
        value = self.front.value  # Get the value of the front node
        self.front = self.front.next  # Move the front pointer to the next node
        if not self.front:
            self.back = None  # If front is None, set back to None as well
        return value

